# Worked focus: http-py-stale-revalidation-invalidation — Choose revalidation, stale serving, explicit invalidation, or bypass while preserving correctness during failure. Demonstrate the result through Python 3.14 urllib, http.client, ssl, typed protocols, and fixture transports.
def worked_http_py_caching_validation_3(age_seconds: int, max_age_seconds: int, etag: str | None) -> dict[str, bool]:
    assert isinstance(age_seconds, int) and isinstance(max_age_seconds, int)
    if age_seconds < 0 or max_age_seconds < 0:
        return {"reusable": False, "revalidate": False}
    reusable = age_seconds <= max_age_seconds
    return {"reusable": reusable, "revalidate": not reusable and bool(etag)}

